const root = $('Cal.com Booking Webhook').first().json;
const body = root.body && typeof root.body === 'object' && !Array.isArray(root.body) ? root.body : root;
const payload = body.payload && typeof body.payload === 'object' && !Array.isArray(body.payload) ? body.payload : body;
const config = $('Get Config').first().json;
const expectedEventTypeId = String(config.calcom?.kickoffEventTypeId || '').trim();
const attendee = Array.isArray(payload.attendees) && payload.attendees.length ? payload.attendees[0] : (payload.attendee && typeof payload.attendee === 'object' ? payload.attendee : {});
const responses = payload.responses && typeof payload.responses === 'object' && !Array.isArray(payload.responses) ? payload.responses : {};
const pick = (...values) => {
  for (const value of values) {
    if (value === undefined || value === null) continue;
    const s = String(value).trim();
    if (s) return s;
  }
  return '';
};
const eventTypeId = pick(payload.eventTypeId, payload.eventType?.id, body.eventTypeId, body.eventType?.id);
const bookingId = pick(payload.bookingId, payload.id, payload.uid, body.bookingId, body.id);
const bookingUrl = pick(payload.bookingUrl, payload.rescheduleUrl, body.bookingUrl);
const meetingUrl = pick(payload.meetingUrl, payload.videoCallUrl, body.meetingUrl);
const startTime = pick(payload.startTime, payload.start, body.startTime, body.start);
const endTime = pick(payload.endTime, payload.end, body.endTime, body.end);
const email = pick(attendee.email, responses.email, payload.email, body.email);
const phone = pick(attendee.phoneNumber, attendee.phone, responses.attendeePhoneNumber, responses.phone, body.phone);
const name = pick(attendee.name, responses.name, payload.name, body.name);
const title = pick(payload.title, body.title);
const shouldHandle = expectedEventTypeId && eventTypeId === expectedEventTypeId ? 'true' : 'false';
return [{
  json: {
    shouldHandle,
    expectedEventTypeId,
    eventTypeId,
    bookingId,
    bookingUrl,
    meetingUrl,
    startTime,
    endTime,
    email,
    phone,
    name,
    title,
    triggerEvent: pick(body.triggerEvent, body.event, payload.event)
  }
}];

const search = $('Find HubSpot Contact by Email').first().json;
const result = Array.isArray(search.results) && search.results.length ? search.results[0] : null;
const props = result?.properties || {};
return [{
  json: {
    contactId: result?.id ? String(result.id) : '',
    firstName: String(props.firstname || '').trim(),
    lastName: String(props.lastname || '').trim(),
    company: String(props.company || '').trim(),
    email: String(props.email || '').trim(),
    phone: String(props.phone || '').trim()
  }
}];

const booking = $('Parse Cal Booking Payload').first().json;
const contact = $('Extract Contact Match').first().json;
const contactName = `${contact.firstName || ''} ${contact.lastName || ''}`.trim() || booking.name || booking.email || 'Unknown attendee';
const company = contact.company || 'Unknown company';
const when = booking.startTime || 'Unknown time';
const lines = [
  `Kickoff call scheduled: ${contactName} (${booking.email || contact.email || 'no email'})`,
  `Company: ${company}`,
  `Start: ${when}`,
  booking.meetingUrl ? `Meet: ${booking.meetingUrl}` : '',
  booking.bookingUrl ? `Booking: ${booking.bookingUrl}` : ''
].filter(Boolean);
return [{
  json: {
    message: lines.join('\n'),
    priority: 'info'
  }
}];

const booking = $('Parse Cal Booking Payload').first().json;
const contact = $('Extract Contact Match').first().json;
const contactName = `${contact.firstName || ''} ${contact.lastName || ''}`.trim() || booking.name || booking.email || 'Unknown attendee';
return [{
  json: {
    workflowName: 'SYS 01 — Cal.com Kickoff Booking Handler',
    contactName,
    phone: booking.phone || contact.phone || '',
    eventType: 'kickoff_call_scheduled',
    status: 'success',
    notes: `booking ${booking.bookingId || 'unknown'}; eventType ${booking.eventTypeId || 'unknown'}; email ${booking.email || contact.email || 'unknown'}; start ${booking.startTime || 'unknown'}`
  }
}];

const booking = $('Parse Cal Booking Payload').first().json;
const contact = $('Extract Contact Match').first().json;
return [{
  json: {
    message: `Kickoff booking received but no HubSpot contact was matched for ${booking.email || 'missing attendee email'}. Booking ${booking.bookingId || 'unknown'} at ${booking.startTime || 'unknown time'}.`,
    priority: 'warning',
    contactName: booking.name || contact.email || booking.email || 'Unknown attendee',
    phone: booking.phone || ''
  }
}];

const booking = $('Parse Cal Booking Payload').first().json;
return [{
  json: {
    workflowName: 'SYS 01 — Cal.com Kickoff Booking Handler',
    contactName: booking.name || booking.email || 'Unknown attendee',
    phone: booking.phone || '',
    eventType: 'kickoff_call_scheduled_unmatched',
    status: 'warning',
    notes: `No HubSpot contact matched email ${booking.email || 'missing'}; booking ${booking.bookingId || 'unknown'}; start ${booking.startTime || 'unknown'}`
  }
}];

const booking = $('Parse Cal Booking Payload').first().json;
let contactId = '';
try {
  contactId = $('Extract Contact Match').first().json.contactId || '';
} catch (error) {}
return [{
  json: {
    success: true,
    handled: booking.shouldHandle === 'true',
    matchedContactId: contactId || null,
    bookingId: booking.bookingId || null
  }
}];
